package genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program.service.VehicleMaintenanceProgramService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/vehicle-maintenance-programs") public class VehicleMaintenanceProgramController { private final VehicleMaintenanceProgramService service; public VehicleMaintenanceProgramController(VehicleMaintenanceProgramService service){this.service=service;} @GetMapping public List<VehicleMaintenanceProgramResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public VehicleMaintenanceProgramResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public VehicleMaintenanceProgramResponse create(@RequestBody VehicleMaintenanceProgramUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public VehicleMaintenanceProgramResponse update(@PathVariable UUID id,@RequestBody VehicleMaintenanceProgramUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
